def evaluate_lowercase_encoded_equals_cluster_registry_case():
    failures = []
    audit_bits: list[str] = []
    default_case_names = {case['name'] for case in DEFAULT_CASES}
    summary_case_names = {case['name'] for case in STATUS_SUMMARY_AUDIT_CASES}

    for base_name in LOWERCASE_ENCODED_EQUALS_CLUSTER_BASES:
        sample_names = [f'{base_name}-{suffix}' for suffix in LOWERCASE_ENCODED_EQUALS_CLUSTER_SAMPLE_SUFFIXES]
        summary_names = [
            f'status-summary-audit-cli-keeps-{base_name}-{suffix}'
            for suffix in LOWERCASE_ENCODED_EQUALS_CLUSTER_AUDIT_SUFFIXES
        ]
        missing_default = [name for name in sample_names if name not in default_case_names]
        missing_summary = [name for name in summary_names if name not in summary_case_names]
        present_default = [name for name in sample_names if name in default_case_names]
        present_summary = [name for name in summary_names if name in summary_case_names]
        audit_bits.append(
            f'{base_name}: samples {len(present_default)}/{len(sample_names)}, summary {len(present_summary)}/{len(summary_names)}'
        )
        if missing_default:
            failures.append(
                f'lowercase-encoded-equals-cluster mist samplecases voor {base_name}: ' + ', '.join(missing_default)
            )
        if missing_summary:
            failures.append(
                f'lowercase-encoded-equals-cluster mist summary-audit-cases voor {base_name}: ' + ', '.join(missing_summary)
            )

    return build_registry_case_result(
        name='registry-keeps-lowercase-encoded-equals-cluster-complete',
        failures=failures,
        audit_bits=audit_bits,
    )


def evaluate_watchdog_full_sweep_registry_case():
    failures = []
    audit_bits: list[str] = []
    module = load_status_module()
    producer_module = load_proof_recheck_producer_module()
    base_named_case_names = set(build_named_case_runners_without_watchdog_batches(module, producer_module).keys())
    named_case_names = set(build_named_case_runners(module, producer_module).keys())

    unknown_special_registry_batches = sorted(
        batch_name
        for batch_name in WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH
        if batch_name not in WATCHDOG_BATCH_CASE_DEPENDENCIES
    )
    duplicate_special_registry_case_names = [
        case_name
        for case_name in unique_case_names(list(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH.values()))
        if list(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH.values()).count(case_name) > 1
    ]
    invalid_special_registry_case_names = sorted(
        case_name
        for case_name in WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH.values()
        if not case_name.startswith('registry-keeps-watchdog-')
        or not case_name.endswith('-route-families-complete')
    )
    redundant_special_registry_batches = sorted(
        batch_name
        for batch_name, case_name in WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH.items()
        if case_name == f'registry-keeps-{batch_name}-route-families-complete'
    )
    resolved_route_family_registry_case_names = build_watchdog_route_family_registry_case_names()
    duplicate_resolved_route_family_registry_case_names = [
        case_name
        for case_name in unique_case_names(resolved_route_family_registry_case_names)
        if resolved_route_family_registry_case_names.count(case_name) > 1
    ]
    actual_watchdog_route_family_registry_case_names = sorted(
        case_name
        for case_name in named_case_names
        if case_name.startswith('registry-keeps-watchdog-')
        and case_name.endswith('-route-families-complete')
    )
    missing_resolved_route_family_registry_case_names = [
        case_name
        for case_name in unique_case_names(resolved_route_family_registry_case_names)
        if case_name not in named_case_names
    ]
    unexpected_watchdog_route_family_registry_case_names = [
        case_name
        for case_name in actual_watchdog_route_family_registry_case_names
        if case_name not in unique_case_names(resolved_route_family_registry_case_names)
    ]
    audit_bits.append(
        'watchdog special route-family registry overrides '
        f'{len(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH) - len(unknown_special_registry_batches)}/{len(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH)} gekoppeld aan bekende batchcases'
    )
    audit_bits.append(
        'watchdog special route-family registry overrides unieke casenamen '
        f'{len(unique_case_names(list(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH.values())))}/{len(WATCHDOG_SPECIAL_ROUTE_FAMILY_REGISTRY_CASE_NAMES_BY_BATCH)}'
    )
    audit_bits.append(
        'watchdog route-family registry resolved unieke casenamen '
        f'{len(unique_case_names(resolved_route_family_registry_case_names))}/{len(resolved_route_family_registry_case_names)}'
    )
    audit_bits.append(
        'watchdog route-family registry resolved aanwezig in named cases '
        f'{len(unique_case_names(resolved_route_family_registry_case_names)) - len(missing_resolved_route_family_registry_case_names)}/{len(unique_case_names(resolved_route_family_registry_case_names))}'
    )
    audit_bits.append(
        'watchdog route-family registry named cases volgen resolved set '
        f'{len(actual_watchdog_route_family_registry_case_names) - len(unexpected_watchdog_route_family_registry_case_names)}/{len(actual_watchdog_route_family_registry_case_names)}'
    )
    if unknown_special_registry_batches:
        failures.append(
            'watchdog special route-family registry overrides verwijzen naar onbekende batchcases: '
            + ', '.join(unknown_special_registry_batches)
        )
    if duplicate_special_registry_case_names:
        failures.append(
            'watchdog special route-family registry overrides bevatten dubbele casenamen: '
            + ', '.join(duplicate_special_registry_case_names)
        )
    if invalid_special_registry_case_names:
        failures.append(
            'watchdog special route-family registry overrides bevatten ongeldige casenamen: '
            + ', '.join(invalid_special_registry_case_names)
        )
    if redundant_special_registry_batches:
        failures.append(
            'watchdog special route-family registry overrides bevatten overbodige default-mappings: '
            + ', '.join(redundant_special_registry_batches)
        )
    if duplicate_resolved_route_family_registry_case_names:
        failures.append(
            'watchdog route-family registry resolved set bevat dubbele casenamen: '
            + ', '.join(duplicate_resolved_route_family_registry_case_names)
        )
    if missing_resolved_route_family_registry_case_names:
        failures.append(
            'watchdog route-family registry resolved set mist named cases: '
            + ', '.join(missing_resolved_route_family_registry_case_names)
        )
    if unexpected_watchdog_route_family_registry_case_names:
        failures.append(
            'watchdog route-family registry named cases bevatten onverwachte casenamen buiten de resolved set: '
            + ', '.join(unexpected_watchdog_route_family_registry_case_names)
        )

    for batch_name, child_case_names in WATCHDOG_BATCH_CASE_DEPENDENCIES.items():
        if batch_name in base_named_case_names:
            failures.append(
                f'watchdog-batchcase {batch_name} botst met bestaande niet-batchcase en zou die stil overschrijven'
            )
        audit_bits.append(
            f'{batch_name}: {0 if batch_name in base_named_case_names else 1}/1 batchnaam zonder niet-batch-collision'
        )
        if batch_name not in named_case_names:
            failures.append(f'watchdog-batchcase ontbreekt in registry: {batch_name}')
            continue

        unique_child_case_names = unique_case_names(child_case_names)
        duplicate_children = [
            case_name
            for index, case_name in enumerate(unique_child_case_names)
            if child_case_names.count(case_name) > 1
        ]
        if not child_case_names:
            failures.append(f'watchdog-batchcase {batch_name} hoort minstens één childcase te hebben')
        if batch_name in unique_child_case_names:
            failures.append(f'watchdog-batchcase {batch_name} mag zichzelf niet als childcase opnemen')
        if duplicate_children:
            failures.append(
                f'watchdog-batchcase {batch_name} bevat dubbele childcases: ' + ', '.join(duplicate_children)
            )

        missing_children = [name for name in unique_child_case_names if name not in named_case_names]
        non_watchdog_children = [name for name in unique_child_case_names if not name.startswith('watchdog-')]
        audit_bits.append(
            f'{batch_name}: {len(unique_child_case_names) - len(missing_children)}/{len(unique_child_case_names)} unieke children aanwezig'
        )
        audit_bits.append(
            f'{batch_name}: {len(unique_child_case_names) - len(non_watchdog_children)}/{len(unique_child_case_names)} children blijven binnen watchdog-namespace'
        )
        if missing_children:
            failures.append(
                f'watchdog-batchcase {batch_name} mist childcases in registry: ' + ', '.join(missing_children)
            )
        if non_watchdog_children:
            failures.append(
                f'watchdog-batchcase {batch_name} mag alleen watchdog-childcases bevatten: '
                + ', '.join(non_watchdog_children)
            )

    def walk_batch_cycles(batch_name: str, path: list[str], visited: set[tuple[str, str]]) -> None:
        for child_case_name in unique_case_names(WATCHDOG_BATCH_CASE_DEPENDENCIES.get(batch_name, [])):
            if child_case_name not in WATCHDOG_BATCH_CASE_DEPENDENCIES:
                continue
            edge = (batch_name, child_case_name)
            if edge in visited:
                continue
            visited.add(edge)
            if child_case_name in path:
                cycle_path = path[path.index(child_case_name):] + [child_case_name]
                failures.append(
                    'watchdog-batchcases mogen geen transitieve cyclus vormen: ' + ' -> '.join(cycle_path)
                )
                continue
            walk_batch_cycles(child_case_name, path + [child_case_name], visited)

    def collect_transitive_case_names(batch_name: str, stack: tuple[str, ...] = ()) -> list[str]:
        if batch_name in stack:
            return []

        expanded_case_names: list[str] = []
        for child_case_name in unique_case_names(WATCHDOG_BATCH_CASE_DEPENDENCIES.get(batch_name, [])):
            expanded_case_names.append(child_case_name)
            if child_case_name in WATCHDOG_BATCH_CASE_DEPENDENCIES:
                expanded_case_names.extend(collect_transitive_case_names(child_case_name, stack + (batch_name,)))
        return expanded_case_names

    visited_edges: set[tuple[str, str]] = set()
    for batch_name in WATCHDOG_BATCH_CASE_DEPENDENCIES:
        walk_batch_cycles(batch_name, [batch_name], visited_edges)

    transitive_case_names_by_batch: dict[str, list[str]] = {}
    for batch_name in WATCHDOG_BATCH_CASE_DEPENDENCIES:
        transitive_case_names = collect_transitive_case_names(batch_name)
        transitive_case_names_by_batch[batch_name] = transitive_case_names
        duplicate_transitive_case_names = [
            case_name
            for case_name in unique_case_names(transitive_case_names)
            if transitive_case_names.count(case_name) > 1
        ]
        audit_bits.append(
            f'{batch_name}: {len(unique_case_names(transitive_case_names))}/{len(transitive_case_names)} transitieve casepaden uniek'
        )
        if duplicate_transitive_case_names:
            failures.append(
                f'watchdog-batchcase {batch_name} bevat dubbel bereikbare transitieve cases: '
                + ', '.join(duplicate_transitive_case_names)
            )

    full_sweep_case_names = unique_case_names(
        ['watchdog-all-routes-full-sweep']
        + transitive_case_names_by_batch.get('watchdog-all-routes-full-sweep', [])
    )
    all_watchdog_case_names = sorted(case_name for case_name in named_case_names if case_name.startswith('watchdog-'))
    missing_from_full_sweep = [
        case_name for case_name in all_watchdog_case_names
        if case_name not in full_sweep_case_names
    ]
    audit_bits.append(
        f'watchdog-all-routes-full-sweep dekt {len(full_sweep_case_names)}/{len(all_watchdog_case_names)} watchdog-cases transitief af'
    )
    if missing_from_full_sweep:
        failures.append(
            'watchdog-all-routes-full-sweep mist watchdog-cases: ' + ', '.join(missing_from_full_sweep)
        )

    nested_batch_count = sum(
        1
        for child_case_names in WATCHDOG_BATCH_CASE_DEPENDENCIES.values()
        for child_case_name in unique_case_names(child_case_names)
        if child_case_name in WATCHDOG_BATCH_CASE_DEPENDENCIES
    )
    audit_bits.append(
        f'watchdog-batchcases transitieve sweep-grafiek gecontroleerd over {len(WATCHDOG_BATCH_CASE_DEPENDENCIES)} batchcases en {nested_batch_count} batch-op-batch-randen'
    )

    return build_registry_case_result(
        name='registry-keeps-watchdog-full-sweep-complete',
        failures=failures,
        audit_bits=audit_bits,
    )


def evaluate_batch_dependency_transitive_full_sweep_registry_case(
    *,
    registry_name: str,
    label: str,
    batch_case_dependencies: dict[str, list[str]],
    full_sweep_batch_name: str,
    required_case_prefixes: str | tuple[str, ...] | None = None,
    required_case_prefix_label: str,
    relevant_case_names: list[str] | None = None,
):
    failures = []
    audit_bits: list[str] = []
    module = load_status_module()
    producer_module = load_proof_recheck_producer_module()
    named_case_names = set(build_named_case_runners(module, producer_module).keys())
    prefix_tuple = None
    if required_case_prefixes is not None:
        prefix_tuple = (required_case_prefixes,) if isinstance(required_case_prefixes, str) else required_case_prefixes

    for batch_name, child_case_names in batch_case_dependencies.items():
        unique_child_case_names = unique_case_names(child_case_names)
        duplicate_children = [
            case_name
            for case_name in unique_child_case_names
            if child_case_names.count(case_name) > 1
        ]
        missing_children = [case_name for case_name in unique_child_case_names if case_name not in named_case_names]
        audit_bits.append(
            f'{batch_name}: {len(unique_child_case_names) - len(missing_children)}/{len(unique_child_case_names)} unieke children aanwezig'
        )
        if not child_case_names:
            failures.append(f'{label}-batchcase {batch_name} hoort minstens één childcase te hebben')
        if batch_name in unique_child_case_names:
            failures.append(f'{label}-batchcase {batch_name} mag zichzelf niet als childcase opnemen')
        if duplicate_children:
            failures.append(
                f'{label}-batchcase {batch_name} bevat dubbele childcases: ' + ', '.join(duplicate_children)
            )
        if missing_children:
            failures.append(
                f'{label}-batchcase {batch_name} mist childcases in registry: ' + ', '.join(missing_children)
            )

    def walk_batch_cycles(batch_name: str, path: list[str], visited: set[tuple[str, str]]) -> None:
        for child_case_name in unique_case_names(batch_case_dependencies.get(batch_name, [])):
            if child_case_name not in batch_case_dependencies:
                continue
            edge = (batch_name, child_case_name)
            if edge in visited:
                continue
            visited.add(edge)
            if child_case_name in path:
                cycle_path = path[path.index(child_case_name):] + [child_case_name]
                failures.append(
                    f'{label}-batchcases mogen geen transitieve cyclus vormen: ' + ' -> '.join(cycle_path)
                )
                continue
            walk_batch_cycles(child_case_name, path + [child_case_name], visited)

    def collect_transitive_case_names(batch_name: str, stack: tuple[str, ...] = ()) -> list[str]:
        if batch_name in stack:
            return []
        expanded_case_names: list[str] = []
        for child_case_name in unique_case_names(batch_case_dependencies.get(batch_name, [])):
            expanded_case_names.append(child_case_name)
            if child_case_name in batch_case_dependencies:
                expanded_case_names.extend(collect_transitive_case_names(child_case_name, stack + (batch_name,)))
        return expanded_case_names

    visited_edges: set[tuple[str, str]] = set()
    for batch_name in batch_case_dependencies:
        walk_batch_cycles(batch_name, [batch_name], visited_edges)

    transitive_case_names_by_batch: dict[str, list[str]] = {}
    for batch_name in batch_case_dependencies:
        transitive_case_names = collect_transitive_case_names(batch_name)
        transitive_case_names_by_batch[batch_name] = transitive_case_names
        duplicate_transitive_case_names = [
            case_name
            for case_name in unique_case_names(transitive_case_names)
            if transitive_case_names.count(case_name) > 1
        ]
        audit_bits.append(
            f'{batch_name}: {len(unique_case_names(transitive_case_names))}/{len(transitive_case_names)} transitieve casepaden uniek'
        )
        if duplicate_transitive_case_names:
            failures.append(
                f'{label}-batchcase {batch_name} bevat dubbel bereikbare transitieve cases: '
                + ', '.join(duplicate_transitive_case_names)
            )

    full_sweep_case_names = unique_case_names(
        [full_sweep_batch_name]
        + transitive_case_names_by_batch.get(full_sweep_batch_name, [])
    )
    if relevant_case_names is None:
        relevant_case_names = sorted(
            case_name for case_name in named_case_names
            if prefix_tuple is not None and case_name.startswith(prefix_tuple)
        )
    else:
        relevant_case_names = unique_case_names(relevant_case_names)
    missing_from_full_sweep = [
        case_name for case_name in relevant_case_names
        if case_name not in full_sweep_case_names
    ]
    audit_bits.append(
        f'{full_sweep_batch_name} dekt {len(full_sweep_case_names)}/{len(relevant_case_names)} {required_case_prefix_label} transitief af'
    )
    if missing_from_full_sweep:
        failures.append(
            f'{full_sweep_batch_name} mist {required_case_prefix_label}: ' + ', '.join(missing_from_full_sweep)
        )

    nested_batch_count = sum(
        1
        for child_case_names in batch_case_dependencies.values()
        for child_case_name in unique_case_names(child_case_names)
        if child_case_name in batch_case_dependencies
    )
    audit_bits.append(
        f'{label}-batchcases transitieve sweep-grafiek gecontroleerd over {len(batch_case_dependencies)} batchcases en {nested_batch_count} batch-op-batch-randen'
    )

    return build_registry_case_result(
        name=registry_name,
        failures=failures,
        audit_bits=audit_bits,
    )


