def evaluate_list_cases_output_case():
    failures = []
    audit_bits: list[str] = []
    expected_watchdog_route_family_registry_case_names = sorted(
        build_watchdog_route_family_registry_case_names()
    )
    filtered_case_names = [
        *build_watchdog_route_family_registry_case_names(),
        'registry-keeps-watchdog-full-sweep-complete',
        'watchdog-alert-consumer-format-passthrough',
        'watchdog-consumer-format-passthrough',
        *WATCHDOG_PROOF_CONTEXT_ALL_ROUTE_CASE_NAMES,
        *list(WATCHDOG_BATCH_CASE_DEPENDENCIES.keys()),
    ]
    actual_watchdog_route_family_registry_case_names = sorted([
        case_name
        for case_name in filtered_case_names
        if case_name.startswith('registry-keeps-watchdog-')
        and case_name.endswith('-route-families-complete')
    ])
    unknown_case_name = 'definitely-not-a-real-regression-case'
    suggested_unknown_case_name = 'regression-check-list-case-output'
    expected_suggested_case_name = 'regression-check-list-cases-output'
    expected_mixed_valid_case_name = 'watchdog-all-routes-full-sweep'
    expected_unknown_cases_message = 'onbekende regressiecase opgegeven'
    duplicate_filtered_case_names = [
        case_name
        for case_name in unique_case_names(filtered_case_names)
        if filtered_case_names.count(case_name) > 1
    ]
    sorted_filtered_case_names = sorted(filtered_case_names)

    missing_watchdog_route_family_registry_case_names = [
        case_name
        for case_name in expected_watchdog_route_family_registry_case_names
        if case_name not in actual_watchdog_route_family_registry_case_names
    ]
    unexpected_watchdog_route_family_registry_case_names = [
        case_name
        for case_name in actual_watchdog_route_family_registry_case_names
        if case_name not in expected_watchdog_route_family_registry_case_names
    ]
    audit_bits.append(
        'watchdog route-family discoverability-cases '
        f'{len(actual_watchdog_route_family_registry_case_names)}/{len(expected_watchdog_route_family_registry_case_names)}'
    )
    audit_bits.append(
        'watchdog discoverability-subset unieke cases '
        f'{len(unique_case_names(filtered_case_names))}/{len(filtered_case_names)}'
    )
    if duplicate_filtered_case_names:
        failures.append(
            'regression-check-list-cases-output bevat dubbele discoverability-cases: '
            + ', '.join(duplicate_filtered_case_names)
        )
    if missing_watchdog_route_family_registry_case_names:
        failures.append(
            'regression-check-list-cases-output mist watchdog route-family discoverability-cases: '
            + ', '.join(missing_watchdog_route_family_registry_case_names)
        )
    if unexpected_watchdog_route_family_registry_case_names:
        failures.append(
            'regression-check-list-cases-output bevat onverwachte watchdog route-family discoverability-cases: '
            + ', '.join(unexpected_watchdog_route_family_registry_case_names)
        )

    def assert_runtime_metadata(payload: dict, label: str) -> None:
        generated_at = payload.get('generated_at')
        started_at = payload.get('started_at')
        generated_at_text = payload.get('generated_at_text')
        started_at_text = payload.get('started_at_text')
        duration_ms = payload.get('duration_ms')
        duration_seconds = payload.get('duration_seconds')
        duration_text = payload.get('duration_text')

        if not isinstance(generated_at, str) or not generated_at:
            failures.append(f'{label} generated_at hoort een niet-lege ISO-tijdstring te zijn')
        else:
            try:
                datetime.fromisoformat(generated_at)
            except ValueError as exc:
                failures.append(f'{label} generated_at hoort parsebare ISO-tijd te zijn, kreeg {exc}')

        if not isinstance(started_at, str) or not started_at:
            failures.append(f'{label} started_at hoort een niet-lege ISO-tijdstring te zijn')
        else:
            try:
                started_dt = datetime.fromisoformat(started_at)
                finished_dt = datetime.fromisoformat(generated_at) if isinstance(generated_at, str) and generated_at else None
                if finished_dt is not None and started_dt > finished_dt:
                    failures.append(f'{label} started_at hoort niet ná generated_at te liggen')
            except ValueError as exc:
                failures.append(f'{label} started_at hoort parsebare ISO-tijd te zijn, kreeg {exc}')

        if not isinstance(generated_at_text, str) or not generated_at_text.strip():
            failures.append(f'{label} generated_at_text hoort een niet-lege teksttimestamp te zijn')
        if not isinstance(started_at_text, str) or not started_at_text.strip():
            failures.append(f'{label} started_at_text hoort een niet-lege teksttimestamp te zijn')
        if not isinstance(duration_ms, int) or duration_ms < 0:
            failures.append(f'{label} duration_ms hoort een niet-negatieve int te zijn')
        if not isinstance(duration_seconds, (int, float)) or duration_seconds < 0:
            failures.append(f'{label} duration_seconds hoort een niet-negatief getal te zijn')
        elif isinstance(duration_ms, int):
            expected_duration_seconds = round(duration_ms / 1000, 3)
            if abs(float(duration_seconds) - expected_duration_seconds) > 0.0005:
                failures.append(
                    f'{label} duration_seconds hoort duration_ms/1000 af te ronden op 3 decimalen'
                )
        if not isinstance(duration_text, str) or not duration_text.endswith('s'):
            failures.append(f'{label} duration_text hoort een secondenlabel te zijn')
        elif isinstance(duration_seconds, (int, float)):
            expected_duration_text = f'{float(duration_seconds):.3f}s'
            if duration_text != expected_duration_text:
                failures.append(
                    f'{label} duration_text hoort exact {expected_duration_text} te spiegelen, kreeg {duration_text}'
                )

    def strip_runtime_metadata(payload: dict) -> dict:
        return {
            key: value
            for key, value in payload.items()
            if key not in {
                'generated_at',
                'generated_at_text',
                'started_at',
                'started_at_text',
                'duration_ms',
                'duration_seconds',
                'duration_text',
            }
        }

    def assert_list_cases_payload_stays_discoverable(payload: dict, label: str) -> None:
        if 'summary' in payload:
            failures.append(f'{label} hoort geen samenvattingsblok mee te geven op de discoverability-route')
        if 'results' in payload:
            failures.append(f'{label} hoort geen results-lijst mee te geven op de discoverability-route')
        if 'failing_case_names' in payload:
            failures.append(f'{label} hoort geen failing_case_names mee te geven op de discoverability-route')
        if 'passed_count' in payload:
            failures.append(f'{label} hoort geen passed_count mee te geven op de discoverability-route')
        if 'failed_count' in payload:
            failures.append(f'{label} hoort geen failed_count mee te geven op de discoverability-route')

    def assert_list_cases_success_payload_avoids_error_fields(payload: dict, label: str) -> None:
        if 'error' in payload:
            failures.append(f'{label} hoort geen error-veld mee te geven bij een geslaagde discoverability-route')
        if 'message' in payload:
            failures.append(f'{label} hoort geen foutmessage mee te geven bij een geslaagde discoverability-route')
        if 'unknown_case_names' in payload:
            failures.append(f'{label} hoort geen unknown_case_names mee te geven bij een geslaagde discoverability-route')
        if 'unknown_case_count' in payload:
            failures.append(f'{label} hoort geen unknown_case_count mee te geven bij een geslaagde discoverability-route')
        if 'suggested_case_names_by_input' in payload:
            failures.append(
                f'{label} hoort geen suggested_case_names_by_input mee te geven bij een geslaagde discoverability-route'
            )

    def assert_list_cases_error_payload_avoids_success_fields(payload: dict, label: str) -> None:
        if 'cases' in payload:
            failures.append(f'{label} hoort geen cases-lijst mee te geven op een foutende discoverability-route')
        if 'case_count' in payload:
            failures.append(f'{label} hoort geen case_count mee te geven op een foutende discoverability-route')

    def assert_unknown_cases_error_message(payload: dict, label: str) -> None:
        if payload.get('message') != expected_unknown_cases_message:
            failures.append(
                f"{label} message verwacht {expected_unknown_cases_message!r}, kreeg {payload.get('message')!r}"
            )

    plain_proc = subprocess.run(
        ['python3', str(ROOT / 'scripts' / 'ai-briefing-regression-check.py'), '--list-cases'],
        cwd=ROOT,
        capture_output=True,
        text=True,
        check=False,
    )
    if plain_proc.returncode != 0:
        failures.append(f'plain --list-cases exitcode verwacht 0, kreeg {plain_proc.returncode}')
    if plain_proc.stderr.strip():
        failures.append('plain --list-cases hoort geen stderr-ruis te geven bij geldige invoer')

    plain_lines = [line.strip() for line in plain_proc.stdout.splitlines() if line.strip()]
    audit_bits.append('plain=' + ', '.join(plain_lines[:8]))
    if not plain_lines:
        failures.append('plain --list-cases gaf geen casenamen terug')
    if plain_lines != sorted(plain_lines):
        failures.append('plain --list-cases hoort alfabetisch gesorteerd te zijn')
    if len(plain_lines) != len(set(plain_lines)):
        failures.append('plain --list-cases hoort geen dubbele casenamen te bevatten')
    for expected_case_name in filtered_case_names:
        if expected_case_name not in plain_lines:
            failures.append(f'plain --list-cases mist verwachte casenaam {expected_case_name}')

    json_proc = subprocess.run(
        ['python3', str(ROOT / 'scripts' / 'ai-briefing-regression-check.py'), '--json', '--list-cases'],
        cwd=ROOT,
        capture_output=True,
        text=True,
        check=False,
    )
    if json_proc.returncode != 0:
        failures.append(f'json --list-cases exitcode verwacht 0, kreeg {json_proc.returncode}')
    if json_proc.stderr.strip():
        failures.append('json --list-cases hoort geen stderr-ruis te geven bij geldige invoer')

    json_payload = {}
    json_stdout = json_proc.stdout.strip() or json_proc.stderr.strip()
    if not json_stdout:
        failures.append('json --list-cases gaf geen output')
    else:
        try:
            json_payload = json.loads(json_stdout)
            audit_bits.append('json=' + json.dumps(json_payload, ensure_ascii=False))
        except json.JSONDecodeError as exc:
            failures.append(f'json --list-cases hoort parsebare JSON te geven, kreeg parsefout: {exc}')

    if json_payload:
        assert_runtime_metadata(json_payload, 'json --list-cases')
        assert_list_cases_payload_stays_discoverable(json_payload, 'json --list-cases')
        assert_list_cases_success_payload_avoids_error_fields(json_payload, 'json --list-cases')
        listed_cases = json_payload.get('cases')
        if not isinstance(listed_cases, list):
            failures.append(f'json --list-cases cases verwacht lijst, kreeg {type(listed_cases).__name__}')
        else:
            if listed_cases != plain_lines:
                failures.append('json --list-cases cases hoort exact gelijk te zijn aan plain --list-cases')
            if json_payload.get('case_count') != len(listed_cases):
                failures.append(
                    'json --list-cases case_count verwacht '
                    f"{len(listed_cases)}, kreeg {json_payload.get('case_count')}"
                )
            if json_payload.get('selected_case_count') != len(listed_cases):
                failures.append(
                    'json --list-cases selected_case_count verwacht '
                    f"{len(listed_cases)}, kreeg {json_payload.get('selected_case_count')}"
                )
        if json_payload.get('ok') is not True:
            failures.append(f"json --list-cases ok verwacht True, kreeg {json_payload.get('ok')}")
