def build_named_case_runners(module, producer_module):
    named_cases = build_named_case_runners_without_watchdog_batches(module, producer_module)

    def build_watchdog_batch_runner(batch_name: str):
        return lambda: evaluate_case_batch(
            name=batch_name,
            case_names=WATCHDOG_BATCH_CASE_DEPENDENCIES[batch_name],
            named_cases=named_cases,
        )

    for watchdog_batch_name in WATCHDOG_BATCH_CASE_DEPENDENCIES:
        named_cases[watchdog_batch_name] = build_watchdog_batch_runner(watchdog_batch_name)

    named_cases['proof-recheck-proof-context-all-routes'] = lambda: evaluate_case_batch(
        name='proof-recheck-proof-context-all-routes',
        case_names=PROOF_RECHECK_PROOF_CONTEXT_ALL_ROUTE_CASE_NAMES,
        named_cases=named_cases,
    )
    named_cases['proof-recheck-consumer-format-passthrough-all-routes'] = lambda: evaluate_case_batch(
        name='proof-recheck-consumer-format-passthrough-all-routes',
        case_names=PROOF_RECHECK_CONSUMER_FORMAT_PASSTHROUGH_ALL_ROUTE_CASE_NAMES,
        named_cases=named_cases,
    )
    named_cases['proof-recheck-all-routes-full-sweep'] = lambda: evaluate_case_batch(
        name='proof-recheck-all-routes-full-sweep',
        case_names=PROOF_RECHECK_ALL_ROUTES_FULL_SWEEP_CASE_NAMES,
        named_cases=named_cases,
    )
    named_cases['status-proof-context-all-routes'] = lambda: evaluate_case_batch(
        name='status-proof-context-all-routes',
        case_names=STATUS_PROOF_CONTEXT_ALL_ROUTE_CASE_NAMES,
        named_cases=named_cases,
    )
    named_cases['brief-consumer-proof-context-all-routes'] = lambda: evaluate_case_batch(
        name='brief-consumer-proof-context-all-routes',
        case_names=BRIEF_CONSUMER_PROOF_CONTEXT_ALL_ROUTE_CASE_NAMES,
        named_cases=named_cases,
    )
    named_cases['briefing-proof-context-all-routes-full-sweep'] = lambda: evaluate_case_batch(
        name='briefing-proof-context-all-routes-full-sweep',
        case_names=BRIEFING_PROOF_CONTEXT_ALL_ROUTES_FULL_SWEEP_CASE_NAMES,
        named_cases=named_cases,
    )

    return named_cases


def main():
    started_at = datetime.now(timezone.utc)
    started_monotonic = monotonic()
    parser = argparse.ArgumentParser(description='Regressiecheck voor AI-briefing output-audits')
    parser.add_argument('--json', action='store_true', help='geef JSON-output')
    parser.add_argument(
        '--case',
        action='append',
        default=[],
        help='draai alleen de opgegeven casenaam (mag meerdere keren)',
    )
    parser.add_argument('--list-cases', action='store_true', help='toon beschikbare casenamen en stop')
    args = parser.parse_args()

    module = load_status_module()
    producer_module = load_proof_recheck_producer_module()
    named_cases = build_named_case_runners(module, producer_module)

    unknown_cases = [case_name for case_name in args.case if case_name not in named_cases]
    if unknown_cases:
        emit_unknown_case_error(
            requested_case_names=args.case,
            unknown_cases=unknown_cases,
            available_case_names=sorted(named_cases.keys()),
            available_case_count=len(named_cases),
            as_json=args.json,
            run_metadata=build_run_metadata(
                started_at=started_at,
                finished_at=datetime.now(timezone.utc),
                duration_ms=int(round((monotonic() - started_monotonic) * 1000)),
            ),
        )
        raise SystemExit(2)

    if args.list_cases:
        requested_case_names = unique_case_names(args.case)
        selected_case_names = sorted(unique_case_names(args.case or list(named_cases.keys())))
        run_metadata = build_run_metadata(
            started_at=started_at,
            finished_at=datetime.now(timezone.utc),
            duration_ms=int(round((monotonic() - started_monotonic) * 1000)),
        )
        if args.json:
            print(json.dumps({
                'ok': True,
                'requested_case_names': requested_case_names,
                'requested_case_count': len(requested_case_names),
                'case_count': len(selected_case_names),
                'cases': selected_case_names,
                'selected_case_names': selected_case_names,
                'selected_case_count': len(selected_case_names),
                'available_case_names': sorted(named_cases.keys()),
                'available_case_count': len(named_cases),
                **run_metadata,
            }, ensure_ascii=False, indent=2))
        else:
            for case_name in selected_case_names:
                print(case_name)
        raise SystemExit(0)

    requested_case_names = unique_case_names(args.case)
    selected_case_names = unique_case_names(args.case or list(named_cases.keys()))
    results = [named_cases[case_name]() for case_name in selected_case_names]
    overall_ok = all(result['ok'] for result in results)
    failing_results = [result for result in results if not result['ok']]
    summary = {
        'case_count': len(results),
        'passed_count': len(results) - len(failing_results),
        'failed_count': len(failing_results),
        'failing_case_names': [result['name'] for result in failing_results],
    }
    run_metadata = build_run_metadata(
        started_at=started_at,
        finished_at=datetime.now(timezone.utc),
        duration_ms=int(round((monotonic() - started_monotonic) * 1000)),
    )

    if args.json:
        print(json.dumps({
            'ok': overall_ok,
            'summary': summary,
            'requested_case_names': requested_case_names,
            'requested_case_count': len(requested_case_names),
            'case_count': summary['case_count'],
            'passed_count': summary['passed_count'],
            'failed_count': summary['failed_count'],
            'failing_case_names': summary['failing_case_names'],
            'selected_case_names': selected_case_names,
            'selected_case_count': len(selected_case_names),
            'available_case_names': sorted(named_cases.keys()),
            'available_case_count': len(named_cases),
            'cases': results,
            'results': results,
            **run_metadata,
        }, ensure_ascii=False, indent=2))
    else:
        for result in results:
            status = 'ok' if result['ok'] else 'FAIL'
            print(f"[{status}] {result['name']}: {result['audit_text']}")
            if result['failures']:
                for failure in result['failures']:
                    print(f"  - {failure}")
        print(
            f"samenvatting: {summary['passed_count']}/{summary['case_count']} ok"
            if overall_ok
            else f"samenvatting: {summary['failed_count']} fail van {summary['case_count']}"
        )
        print('ok' if overall_ok else 'FAIL')

    raise SystemExit(0 if overall_ok else 1)


if __name__ == '__main__':
    if hasattr(signal, 'SIGPIPE'):
        signal.signal(signal.SIGPIPE, signal.SIG_DFL)
    try:
        main()
    except BrokenPipeError:
        try:
            sys.stdout.close()
        finally:
            raise SystemExit(0)
